solution_code:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int *alloc_zeros(int n) {
    return (int *)calloc(n, sizeof(int));
}

int main(void) {
    {
        int *arr = alloc_zeros(5);
        printf("%d\n", (arr) != NULL ? 1 : 0);
        free(arr);
    }
    {
        int *arr = alloc_zeros(4);
        printf("%d\n", (arr) != NULL ? 1 : 0);
        printf("%d\n", (int)(arr[0]));
        printf("%d\n", (int)(arr[1]));
        printf("%d\n", (int)(arr[3]));
        free(arr);
    }
    {
        int *arr = alloc_zeros(3);
        printf("%d\n", (arr) != NULL ? 1 : 0);
        arr[0] = 10; arr[1] = 20; arr[2] = 30;
        printf("%d\n", (int)(arr[0]));
        printf("%d\n", (int)(arr[1]));
        printf("%d\n", (int)(arr[2]));
        free(arr);
    }
    {
        int *arr = alloc_zeros(100);
        printf("%d\n", (arr) != NULL ? 1 : 0);
        printf("%d\n", (int)(arr[50]));
        printf("%d\n", (int)(arr[99]));
        free(arr);
    }
    return 0;
}

